<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>2048 Dark</title>
    <style>
        :root {
            --bg-color: #121212;
            --board-bg: #333;
            --text-color: #eee;
            --tile-empty: #444;
            --tile-2: #eee4da;
            --tile-4: #ede0c8;
            --tile-8: #f2b179;
            --tile-16: #f59563;
            --tile-32: #f67c5f;
            --tile-64: #f65e3b;
            --tile-128: #edcf72;
            --tile-256: #edcc61;
            --tile-512: #edc850;
            --tile-1024: #edc53f;
            --tile-2048: #edc22e;
        }

        body {
            background-color: var(--bg-color);
            color: var(--text-color);
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: center;
            height: 100vh;
            margin: 0;
        }

        .header {
            width: 340px;
            display: flex;
            justify-content: space-between;
            align-items: center;
            margin-bottom: 20px;
        }

        #score-container {
            background-color: var(--board-bg);
            padding: 10px 20px;
            border-radius: 6px;
            text-align: center;
        }

        #score-label {
            font-size: 14px;
            text-transform: uppercase;
            display: block;
            color: #aaa;
        }

        #score {
            font-size: 24px;
            font-weight: bold;
        }

        button {
            padding: 10px 20px;
            background-color: #8f7a66;
            border: none;
            border-radius: 6px;
            color: white;
            font-weight: bold;
            cursor: pointer;
            font-size: 16px;
        }

        button:hover {
            background-color: #7f6a56;
        }

        #board {
            width: 340px;
            height: 340px;
            background-color: var(--board-bg);
            border-radius: 6px;
            display: grid;
            grid-template-columns: repeat(4, 1fr);
            grid-template-rows: repeat(4, 1fr);
            gap: 10px;
            padding: 10px;
            box-sizing: border-box;
        }

        .tile {
            width: 100%;
            height: 100%;
            border-radius: 4px;
            display: flex;
            align-items: center;
            justify-content: center;
            font-size: 28px;
            font-weight: bold;
            transition: all 0.1s ease-in-out;
        }

        /* Tile Colors */
        .tile-0 { background-color: var(--tile-empty); color: transparent; }
        .tile-2 { background-color: var(--tile-2); color: #776e65; }
        .tile-4 { background-color: var(--tile-4); color: #776e65; }
        .tile-8 { background-color: var(--tile-8); color: #f9f6f2; }
        .tile-16 { background-color: var(--tile-16); color: #f9f6f2; }
        .tile-32 { background-color: var(--tile-32); color: #f9f6f2; }
        .tile-64 { background-color: var(--tile-64); color: #f9f6f2; }
        .tile-128 { background-color: var(--tile-128); color: #f9f6f2; font-size: 24px; }
        .tile-256 { background-color: var(--tile-256); color: #f9f6f2; font-size: 24px; }
        .tile-512 { background-color: var(--tile-512); color: #f9f6f2; font-size: 24px; }
        .tile-1024 { background-color: var(--tile-1024); color: #f9f6f2; font-size: 20px; }
        .tile-2048 { background-color: var(--tile-2048); color: #f9f6f2; font-size: 20px; }

    </style>
</head>
<body>

    <div class="header">
        <h1 style="margin:0; font-size: 40px;">2048</h1>
        <div id="score-container">
            <span id="score-label">Score</span>
            <span id="score">0</span>
        </div>
    </div>

    <button id="reset" style="margin-bottom: 20px;">New Game</button>

    <div id="board"></div>

    <script>
        let grid = [];
        let score = 0;
        const size = 4;

        const boardEl = document.getElementById('board');
        const scoreEl = document.getElementById('score');
        const resetBtn = document.getElementById('reset');

        function initGrid() {
            grid = Array(size).fill().map(() => Array(size).fill(0));
        }

        function updateUI() {
            boardEl.innerHTML = '';
            for (let r = 0; r < size; r++) {
                for (let c = 0; c < size; c++) {
                    const val = grid[r][c];
                    const tile = document.createElement('div');
                    tile.className = `tile tile-${val}`;
                    tile.textContent = val === 0 ? '' : val;
                    boardEl.appendChild(tile);
                }
            }
            scoreEl.textContent = score;
        }

        function spawnTile() {
            const emptyCells = [];
            for (let r = 0; r < size; r++) {
                for (let c = 0; c < size; c++) {
                    if (grid[r][c] === 0) emptyCells.push({r, c});
                }
            }
            if (emptyCells.length > 0) {
                const {r, c} = emptyCells[Math.floor(Math.random() * emptyCells.length)];
                grid[r][c] = Math.random() < 0.9 ? 2 : 4;
            }
        }

        function processLine(line) {
            let nonZeros = line.filter(x => x !== 0);
            let newLine = [];
            let addedScore = 0;
            for (let i = 0; i < nonZeros.length; i++) {
                if (i < nonZeros.length - 1 && nonZeros[i] === nonZeros[i+1]) {
                    const val = nonZeros[i] * 2;
                    newLine.push(val);
                    addedScore += val;
                    i++; // Skip the next element as it's merged
                } else {
                    newLine.push(nonZeros[i]);
                }
            }
            while (newLine.length < size) newLine.push(0);
            return { newLine, addedScore };
        }

        function transpose(m) {
            return m[0].map((_, colIndex) => m.map(row => row[colIndex]));
        }

        function move(direction) {
            let newGrid = JSON.parse(JSON.stringify(grid));
            let totalAddedScore = 0;

            const processRows = (m) => {
                let added = 0;
                let newM = m.map(row => {
                    const res = processLine(row);
                    added += res.addedScore;
                    return res.newLine;
                });
                return { newM, added };
            };

            if (direction === 'left') {
                const res = processRows(newGrid);
                newGrid = res.newM;
                totalAddedScore = res.added;
            } else if (direction === 'right') {
                const reversed = newGrid.map(row => [...row].reverse());
                const res = processRows(reversed);
                newGrid = res.newM.map(row => row.reverse());
                totalAddedScore = res.added;
            } else if (direction === 'up') {
                const transposed = transpose(newGrid);
                const res = processRows(transposed);
                newGrid = transpose(res.newM);
                totalAddedScore = res.added;
            } else if (direction === 'down') {
                const transposed = transpose(newGrid);
                const reversed = transposed.map(row => [...row].reverse());
                const res = processRows(reversed);
                newGrid = transpose(res.newM.map(row => row.reverse()));
                totalAddedScore = res.added;
            }

            const changed = JSON.stringify(newGrid) !== JSON.stringify(grid);
            if (changed) {
                grid = newGrid;
                score += totalAddedScore;
                spawnTile();
                updateUI();
                return true;
            }
            return false;
        }

        function reset() {
            initGrid();
            score = 0;
            spawnTile();
            spawnTile();
            updateUI();
        }

        // API for grading
        window.game = {
            size: 4,
            reset: reset,
            move: move,
            board: () => grid.map(row => [...row]),
            setBoard: (arr) => {
                grid = arr.map(row => [...row]);
                updateUI();
            },
            score: () => score
        };

        // Event Listeners
        resetBtn.addEventListener('click', reset);
        window.addEventListener('keydown', (e) => {
            if (['ArrowUp', 'ArrowDown', 'ArrowLeft', 'ArrowRight'].includes(e.key)) {
                e.preventDefault();
                if (e.key === 'ArrowLeft') move('left');
                if (e.key === 'ArrowRight') move('right');
                if (e.key === 'ArrowUp') move('up');
                if (e.key === 'ArrowDown') move('down');
            }
        });

        // Start Game
        reset();
    </script>
</body>
</html>
